    def to_float(value, default=0.0):
        try:
            if value is None:
                return default
            return float(value)
        except (TypeError, ValueError):
            return default

    def pick_value(obj, names):
        if obj is None:
            return None
        if isinstance(obj, dict):
            for name in names:
                if name in obj:
                    value = obj[name]
                    if isinstance(value, dict):
                        value = value.get('price') or value.get('last') or value.get('vwap')
                    if value is not None:
                        try:
