                        except (TypeError, ValueError):
                            pass
        else:
            for name in names:
                value = getattr(obj, name, None)
                if isinstance(value, dict):
                    value = value.get('price') or value.get('last') or value.get('vwap')
                if value is not None:
                    try:
                        return float(value)
                    except (TypeError, ValueError):
                        pass
        return None

    rsi_2 = to_float(state_signals.get(symbol + '_rsi_2', 50.0), 50.0)
    rsi_14 = to_float(state_signals.get(symbol + '_rsi_14', 50.0), 50.0)
    ema_20 = to_float(state_signals.get(symbol + '_ema_20', 0.0), 0.0)

    bars = history.get(symbol, [])
