        price = pick_value(ticker, ('close', 'last', 'vwap', 'lastPrice', 'price'))
        if price is not None:
            prices.append(price)

    close = prices[-1] if prices else ema_20

    bid = pick_value(bars[-1], ('bid', 'bidPrice')) if bars else None
    ask = pick_value(bars[-1], ('ask', 'askPrice')) if bars else None
    mid = (bid + ask) / 2.0 if bid and ask and bid > 0 and ask > 0 else 0.0
    price_side = (close - mid) / mid if mid > 0 and close > 0 else 0.0

    if len(prices) >= 3:
