    else:
        micro_mom = 0.0
        vol = 0.0001
    vol = max(vol, 0.0001)

    buy_threshold = 35.0
    sell_threshold = 65.0

    if ema_20 > 0.0 and close > 0.0:
        ema_dev = (close - ema_20) / ema_20
