        sell_threshold = max(sell_threshold, 63.0)
    elif price_side < -0.00015:
        buy_threshold = min(buy_threshold, 33.0)
        sell_threshold = min(sell_threshold, 67.0)

    if micro_mom < -vol * close * 0.25:
        buy_threshold = min(buy_threshold, 38.0)
    elif micro_mom > vol * close * 0.25:
